noncompliant:
int b = 1;
if (b || someCondition()) { // Noncompliant; 'b' is always true
  doSomething(); // always executed
} else {
  doSomethingElse(); // never executed
}

compliant:
int a = getValue(); // 'a' value depends on runtime
if (a) { // Compliant
  doSomething();
}

if (someCondition()) { // Compliant; condition can vary
  doSomething();
} else {
  doSomethingElse();
}
